package com.infy.inventrack.catalog.config; import com.infy.inventrack.catalog.entity.*; import com.infy.inventrack.catalog.repository.*; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import java.math.BigDecimal; @Configuration public class DataSeeder { @Bean CommandLineRunner seedCatalog(CategoryRepository cats,ProductRepository products){ return args->{ Category electronics=cats.findByNameIgnoreCase("Electronics").orElseGet(()->{Category c=new Category(); c.setName("Electronics"); return cats.save(c);}); if(!products.existsBySku("SKU12300")){ Product p=new Product(); p.setProductName("Laptop"); p.setSku("SKU12300"); p.setPrice(new BigDecimal("88999.00")); p.setImageUrl("http://example.com/laptop.jpg"); p.setCategory(electronics); p.setDescription("High performance laptop"); p.setBrand("HP"); p.setStockQuantity(50); products.save(p); } }; } }
